44	        Context.initializeContext()
45	        InjectionContext.context.register {
46	            bindSingleton(StateMachine.buildStateMachine<GameState, GameEvent>(GameState.Splash, ::stateChanged) {
47	                state(GameState.Splash) {
48	                    action { setScreen<SplashScreen>() }
49	                    edge(GameEvent.LeftSplash, GameState.Setup) {}
50	                }
51	                state(GameState.Setup) {
52	                    action { setScreen<SetupScreen>() }
53	                    edge(GameEvent.StartedGame, GameState.Running) {
54	                        action {
55	                            resetPlayers()
56	                        }
57	                    }
58	                    edge(GameEvent.StartAnimEditor, GameState.AnimEditor) {}
59	                    edge(GameEvent.StartConcept, GameState.Concept) {}
60	                    edge(GameEvent.StartMapEditor, GameState.MapEditor) {}
61	//                    edge(GameEvent.StartCharacterEditor, GameState.CharacterEditor) {}
62	                }
63	                state(GameState.Running) {
64	                    action {
65	                        setScreen<GameScreen>()
66	                        gameScreen.resume()
67	                    }
68	                    edge(GameEvent.PausedGame, GameState.Paused) {}
69	                    edge(GameEvent.GameOver, GameState.Setup) {
70	                        action {
71	                            /*
72	                            Nice stuff. So what do we do here?
73	
74	    //                         */
75	//                        FitnessTracker.fitnessData.sortBy { it.fitness }
76	//                        val lastRelevantIndex = if( FitnessTracker.fitnessData.lastIndex > 5) 5 else FitnessTracker.fitnessData.lastIndex
77	//                        val evolveThese = FitnessTracker.fitnessData.subList(0, lastRelevantIndex)
78	//                        for((index, toEvolve) in evolveThese.withIndex()) {
79	//                            toEvolve.bt.kryoThisBitchToDisk(index + 1)
80	//                        }
81	                        }
82	
83	                    }
84	                }
