93	                    action { setScreen<AnimEditorScreen>() }
94	                    edge(GameEvent.StopAnimEditor, GameState.Setup) {}
95	                }
96	//                state(GameState.CharacterEditor) {
97	//                    action { setScreen<CharacterEditorScreen>() }
98	//                    edge(GameEvent.StopCharacterEditor, GameState.Setup) {}
99	//                }
100	                state(GameState.Concept) {
101	                    action { setScreen<ConceptScreen>() }
102	                    edge(GameEvent.StopConcept, GameState.Setup) {}
103	                }
104	                state(GameState.MapEditor) {
