25	    override fun processEntity(entity: Entity, deltaTime: Float) {
26	        val bodyComponent = AshleyMappers.body.get(entity)
27	        val bodyPosition = bodyComponent.body.position
28	        val bodyRotation = bodyComponent.body.angle
29	        val transformComponent = AshleyMappers.transform.get(entity)
30	        transformComponent.position.set(bodyPosition)
31	        transformComponent.angleRadians = bodyRotation
32	
33	        if(transformComponent.feelsGravity) {
34	            val body = bodyComponent.body
35	            /**
36	             * We must first accelerate
37	             */
38	
39	
40	            if(transformComponent.height > 0f) {
41	                transformComponent.verticalSpeed += g * deltaTime
42	                transformComponent.height += transformComponent.verticalSpeed//Modify with delta time?
43	
44	                body.applyForce(vec2(0f, -g * deltaTime), body.worldCenter, true)
45	            } else {
46	                transformComponent.verticalSpeed = 0f
47	                transformComponent.height = 0f
48	                bodyComponent.body.linearVelocity = vec2(bodyComponent.body.linearVelocity.x, 0f)
49	                if(entity.has<GrenadeComponent>()) {
50	                    contactManager.handleGrenadeHittingAnything(ContactType.GrenadeHittingAnything(entity))
51	                }
52	                if(entity.has<MolotovComponent>()) {
53	                    contactManager.handleMolotovHittingAnything(ContactType.MolotovHittingAnything(entity))
54	                }
55	            }
56	
57	
58	
59	        }
60	    }
