151	fun Contact.thisIsAContactBetween(): ContactType {
152	    if(this.justOneHas<AgentProperties>()) {
153	        val entity = this.getEntityFor<AgentProperties>()
154	        val otherFixture = if(this.fixtureA.isEntity() && entity == this.fixtureA.getEntity()) this.fixtureB else this.fixtureA
155	
156	        if(!otherFixture.isEntity()) {
157	            //This is a wall, for sure
158	            return ContactType.EnemyAndObstacle(entity)
159	        } else if(otherFixture.getEntity().hasObstacle()) {
160	            return ContactType.EnemyAndObstacle(entity)
161	        }
162	    }
163	    if (this.justOneHas<DamageEffectComponent>()) {
164	        val damageEffectEntity = this.getEntityFor<DamageEffectComponent>()
165	        if (this.bothAreEntities()) {
166	            val otherEntity = this.getOtherEntity(damageEffectEntity)
167	            return if (otherEntity.has<PlayerComponent>()) {
168	                ContactType.PlayerAndDamage(damageEffectEntity, otherEntity)
169	            } else if (otherEntity.has<AgentProperties>()) {
170	                ContactType.EnemyAndDamage(damageEffectEntity, otherEntity)
171	            } else {
172	                ContactType.SomeEntityAndDamage(damageEffectEntity, otherEntity)
173	            }
174	        } else {
175	            ContactType.DamageAndWall(damageEffectEntity)
176	        }
177	    }
178	
179	    if (this.isPlayerByPlayerContact()) {
180	        return if (this.justOneHas<PlayerWaitsForRespawn>()) {
181	            val deadPlayer = this.getEntityFor<PlayerWaitsForRespawn>()
182	            val otherPlayer = this.getOtherEntity(deadPlayer)
183	            ContactType.PlayerAndDeadPlayer(otherPlayer, deadPlayer)
184	        } else {
185	            ContactType.PlayerCloseToPlayer(this.fixtureA.getEntity(), this.fixtureB.getEntity())
186	        }
187	    }
188	
189	    if (this.isPlayerContact()) {
190	        if (this.atLeastOneHas<LootComponent>()) {
191	            val playerEntity = this.getPlayerFor().entity
192	            val lootEntity = this.getEntityFor<LootComponent>()
193	
194	            return ContactType.PlayerAndLoot(playerEntity, lootEntity)
195	        }
196	        if(this.atLeastOneHas<ComplexActionComponent>()) {
197	            val playerEntity = this.getPlayerFor().entity
198	            val other = this.getEntityFor<ComplexActionComponent>()
199	            return ContactType.PlayerAndComplexAction(playerEntity, other)
200	        }
201	        if (this.atLeastOneHas<ShotComponent>()) {
202	            val playerEntity = this.getPlayerFor().entity
203	            return ContactType.PlayerAndProjectile(this.getPlayerFor().entity, this.getOtherEntity(playerEntity))
204	        }
205	        if (this.atLeastOneHas<EnemySensorComponent>()) {
206	            val enemy = this.getEntityFor<EnemySensorComponent>()
207	            val player = this.getOtherEntity(enemy)
208	            return ContactType.EnemySensesPlayer(enemy, player)
209	        }
210	        if (this.atLeastOneHas<ObjectiveComponent>()) {
211	            val cEntity = this.getEntityFor<ObjectiveComponent>()
212	            return ContactType.PlayerAndObjective(this.getPlayerFor().entity, cEntity)
213	        }
214	        if (this.noSensors() && this.atLeastOneHas<TackleComponent>()) {
215	            val enemy = this.getEntityFor<TackleComponent>()
216	            val player = this.getOtherEntity(enemy)
217	            return ContactType.PlayerAndSomeoneWhoTackles(player, enemy)
218	        }
219	    }
220	
221	    if (this.bothHaveComponent<EnemySensorComponent>()) {
222	        /*
223	        This is an enemy noticing an enemy - if that enemy is chasing the player, then both should do that!
224	         */
225	        val enemyAEntity = this.fixtureA.getEntity()
226	        val enemyBEntity = this.fixtureB.getEntity()
227	        return ContactType.EnemyAndEnemy(enemyAEntity, enemyBEntity)
228	    }
229	
230	    if (this.atLeastOneHas<AgentProperties>() && this.atLeastOneHas<BulletComponent>()) {
231	
232	        val enemy = this.getEntityFor<AgentProperties>()
233	        val bulletEntity = this.getEntityFor<BulletComponent>()
234	        return ContactType.EnemyAndBullet(enemy, bulletEntity)
235	    }
236	
237	    if (this.atLeastOneHas<MolotovComponent>()) {
238	        /*
239	        Lets not add a new entity, let's modify the one we have
240	         */
241	        val molotov = this.getEntityFor<MolotovComponent>()
242	        return ContactType.MolotovHittingAnything(molotov)
243	    }
244	    if (this.atLeastOneHas<GrenadeComponent>()) {
245	        /*
246	        Lets not add a new entity, let's modify the one we have
247	         */
248	        val grenade = this.getEntityFor<GrenadeComponent>()
249	        return ContactType.GrenadeHittingAnything(grenade)
250	    }
251	    return ContactType.Unknown
252	}

