15	        val pc = entity.getComponent<PlayerComponent>()
16	        val ap = entity.getComponent<AttackableProperties>()
17	
18	
19	        if (ap.isDead && pc.player.lives > 0 && !entity.has<PlayerWaitsForRespawn>() && !entity.has<PlayerIsRespawning>()) {
20	            pc.player.lives -= 1
21	            entity.add(engine.createComponent(PlayerWaitsForRespawn::class.java))
22	        } else if (ap.isDead && pc.player.lives <= 0) {
23	            entity.add(engine.createComponent(PlayerIsDead::class.java))
24	        }
25	
26	        if (entity.has<PlayerIsDead>() || entity.has<PlayerWaitsForRespawn>()) {
27	            if (PlayerControlComponent.has(entity)) {
28	                val controlComponent = PlayerControlComponent.get(entity)
29	                controlComponent.waitsForRespawn = true
30	            }
31	        }
32	
33	        if (entity.has<PlayerWaitsForRespawn>()) {
34	            val dc = entity.getComponent<PlayerWaitsForRespawn>()
35	            dc.coolDown -= deltaTime
36	            if (dc.coolDown < 0f) {
37	                entity.remove(PlayerWaitsForRespawn::class.java)
38	                entity.add(engine.createComponent(PlayerIsRespawning::class.java))
39	                ap.health = GameConstants.ENEMY_BASE_HEALTH
40	            }
41	        }
42	        if (entity.has<PlayerIsRespawning>()) {
43	            val rc = entity.getComponent<PlayerIsRespawning>()
44	            rc.coolDown -= deltaTime
45	            if (rc.coolDown < 0f) {
46	                entity.remove(PlayerIsRespawning::class.java)
