263	
264	fun bodyForRegion(
265	    at: Vector2,
266	    colliderCategoryBits: Short,
267	    colliderMaskBits: Short,
268	    detectorBits: Short,
269	    detectorMaskBits: Short,
270	    sensorBits: Short,
271	    sensorMaskBits: Short,
272	    pixelWidth: Int = 24,
273	    pixelHeight: Int = 48
274	): Body {
275	    val widthInMeters = pixelWidth / PIXELS_PER_METER
276	    val heightInMeters = pixelHeight / PIXELS_PER_METER
277	
278	    val bottomBoxWidth = widthInMeters
279	    val bottomBoxHeight = widthInMeters / 2
280	    val halfHeight = heightInMeters / 2
281	
282	    val box2dBody = world().body {
283	        type = BodyDef.BodyType.DynamicBody
284	        position.set(at)
285	        fixedRotation = true
286	        //Bottom projection box
287	        box(bottomBoxWidth, bottomBoxHeight, vec2(0f, halfHeight - bottomBoxHeight / 2)) {
288	            density = PLAYER_DENSITY
289	            filter {
290	                categoryBits = colliderCategoryBits
291	                maskBits = colliderMaskBits
292	            }
293	        }
294	        box(widthInMeters, heightInMeters, vec2(0f, 0f)) {
295	            isSensor = true
296	            filter {
297	                categoryBits = detectorBits
298	                maskBits = detectorMaskBits
299	            }
300	        }
301	        circle(2.5f * heightInMeters, vec2(0f, 0f)) {
302	            isSensor = true
303	            filter {
304	                categoryBits = sensorBits
305	                maskBits = sensorMaskBits
306	            }
307	        }
308	        linearDamping = SHIP_LINEAR_DAMPING
309	        angularDamping = SHIP_ANGULAR_DAMPING
310	    }
311	    return box2dBody
312	}
